        # dev.off()
        # SimilarityPlot[index_retrieval]<-paste0('<img src="',
        #                                         gsub(x=unlist(strsplit(spectralsimilarityfile, "www"))[length(unlist(strsplit(spectralsimilarityfile, "www")))],
        #                                              pattern="/spectral_match",
        #                                              replacement="./spectral_match")
        #                                         , '" height="380"></img>')
        
        df1<-data.frame("score"=spectralsimilarity,"record"=max_spectral_similarity_score,
                        "linkmassbank"=max_spectral_similarity_score_display)
        msms_peaklist
        reference_spectra[[whichmaxspectralsimilarity]][,-2]
        
        data_list <- list(result = df1, msmsqueried = msms_peaklist, referencespectra = reference_spectra[[whichmaxspectralsimilarity]][,-2])
        
        json_data <- toJSON(data_list, pretty = TRUE)
        
      } else {
        df1<-data.frame("score"="","record"="","linkmassbank"="")
        df1<-df1[-1,]
        
        msms_peaklist<-data.frame("mz"="","int"="")
        msms_peaklist<-msms_peaklist[-1,]
        
        referencespectra<-data.frame("mz"="","norm_int"="")
        referencespectra<-referencespectra[-1,]
        
        data_list <- list(result = df1, msmsqueried = msms_peaklist, referencespectra = referencespectra)
        
        json_data <- toJSON(data_list, pretty = TRUE)
      }
    } else {
      df1<-data.frame("score"="","record"="","linkmassbank"="")
      df1<-df1[-1,]
      
      msms_peaklist<-data.frame("mz"="","int"="")
      msms_peaklist<-msms_peaklist[-1,]
      
      referencespectra<-data.frame("mz"="","norm_int"="")
      referencespectra<-referencespectra[-1,]
      
      data_list <- list(result = df1, msmsqueried = msms_peaklist, referencespectra = referencespectra)
      json_data <- toJSON(data_list, pretty = TRUE)
    }
    
    return(json_data)
}

